pragma solidity ^0.8.21;

import {ECDSA} from "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import {Ownable} from "./Ownable.sol";

abstract contract Guarded is Ownable {
  using ECDSA for bytes32;

  // storage

  mapping(address => bool) internal _guardians;

  // events

  event GuardianAdded(address guardian);

  event GuardianRemoved(address guardian);

  // errors

  error MsgSenderIsNotTheContractGuardian();

  error GuardianIsTheZeroAddress();

  error GuardianAlreadyExists();

  error GuardianDoesntExist();

  error InvalidGuardianSignature();

  // deployment

  constructor(address owner) Ownable(owner) {
    //
  }

  // external getters

  function hasGuardian(address guardian) external view returns (bool) {
    return _hasGuardian(guardian);
  }

  // external setters

  function addGuardian(address guardian) external onlyOwner {
    if (guardian == address(0)) {
      revert GuardianIsTheZeroAddress();
    }

    if (_guardians[guardian]) {
      revert GuardianAlreadyExists();
    }

    _guardians[guardian] = true;

    emit GuardianAdded(guardian);
  }

  function removeGuardian(address guardian) external onlyOwner {
    if (guardian == address(0)) {
      revert GuardianIsTheZeroAddress();
    }

    if (!_guardians[guardian]) {
      revert GuardianDoesntExist();
    }

    delete _guardians[guardian];

    emit GuardianRemoved(guardian);
  }

  // internal getters

  function _verifyGuardianSignature(
    bytes32 hash,
    bytes calldata signature
  ) internal view virtual {
    if (!_hasGuardian(hash.recover(signature))) {
      revert InvalidGuardianSignature();
    }
  }

  function _hasGuardian(address guardian) internal view returns (bool) {
    return guardian == _owner || _guardians[guardian];
  }

  // internal setters

  function _addGuardians(address[] calldata guardians) internal {
    uint256 len = guardians.length;

    for (uint256 index; index < len; ) {
      address guardian = guardians[index];

      if (guardian == address(0)) {
        revert GuardianIsTheZeroAddress();
      }

      if (_guardians[guardian]) {
        revert GuardianAlreadyExists();
      }

      _guardians[guardian] = true;

      unchecked {
        index += 1;
      }
    }
  }
}
","keccak256":"0xf27fa5a2cd0b175a1067fc8182cbb7b7bbce5acc82450fa2b93af43c1dd83125","license":"None"},"contracts/access/Ownable.sol":{"content":"// SPDX-License-Identifier: None
pragma solidity 0.8.21;

import {GatewayRecipient} from "../gateway/GatewayRecipient.sol";

abstract contract Ownable is GatewayRecipient {
  // storage

  address internal _owner;

  // events

  event OwnerUpdated(address owner);

  // errors

  error MsgSenderIsNotTheContractOwner();

  error OwnerIsTheZeroAddress();

  // modifiers

  modifier onlyOwner() {
    if (_msgSender() != _owner) {
      revert MsgSenderIsNotTheContractOwner();
    }

    _;
  }

  // deployment

  constructor(address owner) {
    _owner = owner == address(0) ? msg.sender : owner;
  }

  // external getters

  function getOwner() external view returns (address) {
    return _owner;
  }

  // external setters

  function setOwner(address owner) external onlyOwner {
    if (owner == address(0)) {
      revert OwnerIsTheZeroAddress();
    }

    _owner = owner;

    emit OwnerUpdated(owner);
  }
}
","keccak256":"0xdc9ed4faefa9613b8b6d6857ab889a2aab62cd32342391261f38532b17bb5990","license":"None"},"contracts/gateway/GatewayRecipient.sol":{"content":"// SPDX-License-Identifier: None
pragma solidity 0.8.21;

import {Context} from "@openzeppelin/contracts/utils/Context.sol";

abstract contract GatewayRecipient is Context {
  // storage

  address internal _gateway;

  // external getters

  function getGateway() external view returns (address) {
    return _gateway;
  }

  // internal getters

  function _msgSender()
    internal
    view
    virtual
    override
    returns (address sender)
  {
    if (msg.sender == _gateway) {
      // solhint-disable-next-line no-inline-assembly
      assembly {
        sender := shr(96, calldataload(sub(calldatasize(), 20)))
      }
    } else {
      sender = super._msgSender();
    }

    return sender;
  }
}
